code.java:
public int arrayPairSum(int[] nums) {
    Arrays.sort(nums);
    int sum = 0;
    for(int i = 0; i < nums.length; i += 2){
        sum += nums[i];
    }
    return sum;
}

code.python:
def arrayPairSum(nums):
    nums.sort()
    ans = 0
    for i in range(0, len(nums), 2):
        ans += nums[i]
    return ans

code.cpp:
int arrayPairSum(vector<int>& nums){
    sort(nums.begin(), nums.end());
    int sum=0;
    for(int i=0;i<nums.size();i+=2)
        sum+=nums[i];
    return sum;
}

